* CDS View Extension (add custom field to standard view)
extend view I_PurchaseOrderItem with ZX_PO_ITEM_EXT
{
  ekpo.zzproject_code as ProjectCode  " Custom field from append
}

* The append structure (created via extensibility framework):
* Structure: ZZ1_EKPO (append to EKPO)
* Field: ZZPROJECT_CODE CHAR 20

* Expose via projection view annotation:
@UI.lineItem: [{ position: 150, label: 'Project Code' }]
@UI.fieldGroup: [{ qualifier: 'Header', position: 150 }]
ProjectCode;

managed implementation in class zcl_bp_custorder distinct;
define behavior for ZI_CustomerOrder alias CustOrder
persistent table zcust_orders
locking master
authorization master ( instance )
etag master EtagTimestamp
{
  create;
  update;
  delete (features : instance);  " Conditional delete

  field (readonly) : OrderId, CreatedAt;
  field (mandatory : create) : CustomerId, OrderDate;

  validation validatePaymentTerms
    on save { field PaymentTerms; }
  determination setDeliveryDate
    on modify { field OrderDate; }
  action submitOrder result [1] $self;
  draft;
}

* Interface View (no UI annotations, pure data)
define view ZI_PurchaseOrder
  as select from ekko as po
  inner join ekpo as item on ...
{
  key po.ebeln  as PurchaseOrder,
      item.ebelp as PurchaseOrderItem,
      po.lifnr   as Supplier,
      item.matnr as Material,
      item.menge as OrderQuantity
}

* Projection View (UI-specific, adds annotations)
@UI.headerInfo: { typeName: 'Purchase Order' }
define view ZC_PurchaseOrderApproval
  as projection on ZI_PurchaseOrder
{
  @UI.lineItem: [{ position: 10 }]
  @UI.selectionField: [{ position: 10 }]
  PurchaseOrder,
  @UI.lineItem: [{ position: 20 }]
  Supplier,
  @UI.lineItem: [{ position: 30 }]
  OrderQuantity
}
